<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">font-size</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: 7px; </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">letter-spacing</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: 3px; </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">font-weight</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: 700;</span></span>
